INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Program: B.Tech and B.Des (2025 batch, tentative).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > First semester total: Rs 1,42,000 (tuition Rs 1,00,000, insurance Rs 1,600, per-semester fees Rs 6,300, one-time admission Rs 8,100, refundable deposit Rs 10,000, accommodation Rs 16,000).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Second semester total: Rs 1,22,300.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Third semester total: Rs 1,23,900.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Subsequent semesters: approximately Rs 1,22,000 to Rs 1,24,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Total 4 years (8 semesters): approximately Rs 9,90,000 to Rs 10,00,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > SC/ST/PwD exempted from tuition fee.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Income below Rs 1 lakh: full tuition remission (Rs 1,00,000 per semester).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Indore', 'fee_structure', 'Fee Structure > Income Rs 1-5 lakh: 2/3rd tuition remission (Rs 66,667 per semester).');
